#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        for(int i=1;i<=N;i++){
            int val = (i==N)?1:i+1;
            printf("%d",val);
            if(i<N) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

